   584→    public CompletableFuture<CompletedCheckpoint> triggerCheckpoint(CheckpointType checkpointType) {
   585→
   586→        if (checkpointType == null) {
   587→            throw new IllegalArgumentException("checkpointType cannot be null");
   588→        }
   589→
   590→        final SnapshotType snapshotType;
   591→        switch (checkpointType) {
   592→            case CONFIGURED:
   593→                snapshotType = checkpointProperties.getCheckpointType();
   594→                break;
   595→            case FULL:
   596→                snapshotType = FULL_CHECKPOINT;
   597→                break;
   598→            case INCREMENTAL:
   599→                snapshotType = CHECKPOINT;
   600→                break;
   601→            default:
   602→                throw new IllegalArgumentException("unknown checkpointType: " + checkpointType);
   603→        }
   604→
   605→        final CheckpointProperties properties =
   606→                new CheckpointProperties(
   607→                        checkpointProperties.forceCheckpoint(),
   608→                        snapshotType,
   609→                        checkpointProperties.discardOnSubsumed(),
   610→                        checkpointProperties.discardOnJobFinished(),
   611→                        checkpointProperties.discardOnJobCancelled(),
   612→                        checkpointProperties.discardOnJobFailed(),
   613→                        checkpointProperties.discardOnJobSuspended(),
   614→                        checkpointProperties.isUnclaimed());
